def solve(claims):
    if not isinstance(claims, list):
        raise ValueError("Input must be a list of claims.")

    for claim in claims:
        if not isinstance(claim, dict):
            raise ValueError("Each claim must be a dictionary.")
        if 'amount' not in claim or not isinstance(claim['amount'], (int, float)):
            raise ValueError("Each claim must have a numeric 'amount' field.")

    # Core logic to identify potential fraud
    potential_fraud = []
    for claim in claims:
        if claim['amount'] > 10000:  # Example threshold for potential fraud
            potential_fraud.append(claim)

    return potential_fraud
